  ('disabled-7c4986e7-moex-00008', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-114-6948958a', 'sub-disabled-7c4986e7-01', NULL, 'single_choice', '假設租屋市場為完全競爭市場，市場的供給函數為Q=P，而市場的需求函 數為Q=50,000P，其中P為租金、Q為租屋數量。在目前的租金管制上 限$10,000之下，市場出租房屋的數量為何？', '["10,000", "25,000", "40,000", "50,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "b8525077d2fd", "answer_pdf_sha1": "4fb29f00a092", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "407", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
